def collect_erpnext_artifacts(branch=ERP_NEXT_BRANCH, max_files=40):
    print("[Agent 1A] Connecting to ERPNext GitHub repository...")
    accounting_keywords = [
        "account", "accounts", "accounting", "journal", "journal_entry",
        "general_ledger", "gl_entry", "ledger", "invoice", "sales_invoice",
        "purchase_invoice", "payment_entry", "payment", "bank", "banking",
        "tax", "company", "cost_center", "asset", "liability", "revenue", "expense"
    ]
    tree_url = f"https://api.github.com/repos/{ERP_NEXT_OWNER}/{ERP_NEXT_REPO}/git/trees/{branch}?recursive=1"
    headers = {}
    token = os.environ.get("GITHUB_TOKEN")
    if token:
        headers["Authorization"] = f"token {token}"
    try:
        response = requests.get(tree_url, headers=headers, timeout=25)
        response.raise_for_status()
        tree_items = response.json().get("tree", [])
        candidate_paths = []
        for item in tree_items:
            path = item.get("path", "")
            item_type = item.get("type", "")
            lower_path = path.lower()
            if item_type != "blob": continue
            if not lower_path.endswith((".json", ".csv", ".py", ".md", ".txt")): continue
            if any(keyword in lower_path for keyword in accounting_keywords): candidate_paths.append(path)
        candidate_paths = candidate_paths[:max_files]
        records = []
        for path in candidate_paths:
            raw_url = f"https://raw.githubusercontent.com/{ERP_NEXT_OWNER}/{ERP_NEXT_REPO}/{branch}/{path}"
            detected = sorted({kw for kw in accounting_keywords if kw in path.lower()})
            artifact_type = "ERPNext source artifact"
            if path.lower().endswith(".json"): artifact_type = "ERPNext JSON DocType/configuration artifact"
            elif path.lower().endswith(".csv"): artifact_type = "ERPNext CSV fixture/tabular artifact"
            elif path.lower().endswith(".py"): artifact_type = "ERPNext Python business logic/test artifact"
            elif path.lower().endswith(".md"): artifact_type = "ERPNext documentation artifact"
            records.append({"repository": f"{ERP_NEXT_OWNER}/{ERP_NEXT_REPO}", "branch": branch, "source_path": path, "raw_url": raw_url, "artifact_type": artifact_type, "detected_keywords": ", ".join(detected)})
        artifacts_df = pd.DataFrame(records)
        if artifacts_df.empty: print("[Agent 1A] No ERPNext artifacts found. Fallback metadata will be used.")
        else: artifacts_df.to_csv("data/erpnext_github_artifacts.csv", index=False); print(f"[Agent 1A] ERPNext artifacts collected: {len(artifacts_df)}"); print("[Agent 1A] Saved: data/erpnext_github_artifacts.csv")
        return artifacts_df
    except Exception as e: print(f"[Agent 1A] ERPNext GitHub ingestion failed: {e}"); return pd.DataFrame()

