def preprocessing_agent(df):
    cleaned_df = df.drop_duplicates().ffill().bfill().copy()
    cleaned_df["Balance_Variance"] = (cleaned_df["Debit_Value"] - cleaned_df["Credit_Value"]).abs()
    numeric_cols = ["Debit_Value", "Credit_Value", "Procurement_Waste_Tons", "Balance_Variance"]
    scaler = StandardScaler()
    scaled_array = scaler.fit_transform(cleaned_df[numeric_cols])
    for i, col in enumerate(numeric_cols): cleaned_df[f"scaled_{col}"] = scaled_array[:, i]
    print("[Agent 2] Preprocessing complete."); return cleaned_df

# Cell 8GzLaqS_Vmyu content (multi_bert_agent)
def keyword_score(text, terms):
    text = str(text).lower()
    matches = sum(1 for term in terms if term in text)
    return min(matches / max(len(terms), 1), 1.0)

def multi_bert_agent(df):
    df = df.copy()
    print("[Agent 3] Loading SentenceTransformer model...")
    # Ensure embedder is loaded only once
    if 'embedder_multi_bert' not in globals():
        global embedder_multi_bert
        embedder_multi_bert = SentenceTransformer("all-MiniLM-L6-v2")
    
    combined_text = (df["Financial_Narrative"].astype(str) + " " + df["ESG_Disclosure"].astype(str) + " " + df["Cyber_Disclosure"].astype(str) + " " + df["ERPNext_Source_Path"].astype(str)).tolist()
    embeddings = embedder_multi_bert.encode(combined_text, show_progress_bar=False)
    ledger_terms = ["bypass", "suspense", "manual", "adjustment", "root", "without secondary", "period-end"]
    cyber_terms = ["patch", "legacy", "bypass", "identity", "access", "security", "firewall", "encryption"]
    esg_terms = ["waste", "net-zero", "emissions", "ecological", "sustainable", "recycled", "green", "privacy"]
    df["SubAgent_A_GeneralBERT_Risk"] = np.clip(np.var(embeddings, axis=1), 0, 1)
    df["SubAgent_B_LedgerBERT_Risk"] = df["Financial_Narrative"].apply(lambda x: keyword_score(x, ledger_terms))
    df["SubAgent_C_CyberBERT_Risk"] = df["Cyber_Disclosure"].apply(lambda x: keyword_score(x, cyber_terms))
    df["SubAgent_D_ESGBERT_Risk"] = df["ESG_Disclosure"].apply(lambda x: keyword_score(x, esg_terms))
    df["Text_Embedding_Proxy"] = np.mean(embeddings, axis=1)
    print("[Agent 3] Multi-BERT proxy scoring complete."); return df, embeddings

# Cell aka3XzTbVmyu content (autoencoder_anomaly_agent)
class PyTorchAutoencoder(nn.Module):
    def __init__(self, input_dim):
        super().__init__()
        self.encoder = nn.Sequential(nn.Linear(input_dim, 6), nn.Tanh(), nn.Linear(6, 3))
        self.decoder = nn.Sequential(nn.Linear(3, 6), nn.Tanh(), nn.Linear(6, input_dim))
    def forward(self, x): return self.decoder(self.encoder(x))

def autoencoder_anomaly_agent(df, threshold_percentile=85, epochs=160, lr=0.03):
    df = df.copy(); torch.manual_seed(SEED)
    feature_cols = [
        "scaled_Debit_Value", "scaled_Credit_Value", "scaled_Procurement_Waste_Tons",
        "scaled_Balance_Variance", "SubAgent_A_GeneralBERT_Risk", "SubAgent_B_LedgerBERT_Risk",
        "SubAgent_C_CyberBERT_Risk", "SubAgent_D_ESGBERT_Risk", "Text_Embedding_Proxy"
    ]
    # Filter feature_cols to only include those present in df
    actual_feature_cols = [col for col in feature_cols if col in df.columns]
    
    X = df[actual_feature_cols].astype(float).values; X_tensor = torch.tensor(X, dtype=torch.float32)
    model = PyTorchAutoencoder(input_dim=len(actual_feature_cols)); criterion = nn.MSELoss(); optimizer = torch.optim.Adam(model.parameters(), lr=lr)
    model.train();
    for epoch in range(epochs): optimizer.zero_grad(); outputs = model(X_tensor); loss = criterion(outputs, X_tensor); loss.backward(); optimizer.step()
    model.eval();
    with torch.no_grad(): reconstructed = model(X_tensor); errors = torch.mean((X_tensor - reconstructed) ** 2, dim=1).numpy()
    threshold_value = np.percentile(errors, threshold_percentile)
    df["Reconstruction_Error"] = errors; df["Autoencoder_Threshold"] = threshold_value
    df["Anomaly_Indicator"] = df["Reconstruction_Error"].apply(lambda e: "CRITICAL PROFILE ALERT" if e > threshold_value else "Normal Verified Ledger")
    print("[Agent 4A] PyTorch Autoencoder anomaly detection complete."); return df

# Cell klDtWkr9Vmyv content (isolation_forest_agent)
def isolation_forest_agent(df, text_embeddings, contamination=0.30):
    df = df.copy()
    structured_cols = [
        "scaled_Debit_Value", "scaled_Credit_Value", "scaled_Procurement_Waste_Tons",
        "scaled_Balance_Variance", "SubAgent_B_LedgerBERT_Risk", "SubAgent_C_CyberBERT_Risk",
        "SubAgent_D_ESGBERT_Risk"
    ]
    # Filter structured_cols to only include those present in df
    actual_structured_cols = [col for col in structured_cols if col in df.columns]

    structured_features = df[actual_structured_cols].astype(float).values
    
    # Ensure text_embeddings are available and match df length
    if text_embeddings is not None and len(text_embeddings) == len(df):
        combined_features = np.hstack([text_embeddings, structured_features])
    else:
        # Fallback if text_embeddings are missing or malformed
        print("Warning: text_embeddings not available or length mismatch. Using only structured features for Isolation Forest.")
        combined_features = structured_features

    model = IsolationForest(contamination=contamination, random_state=SEED); pred = model.fit_predict(combined_features)
    df["IForest_Anomaly"] = [1 if p == -1 else 0 for p in pred]
    df["IForest_Indicator"] = df["IForest_Anomaly"].apply(lambda x: "CRITICAL PROFILE ALERT" if x == 1 else "Normal Verified Ledger")
    print("[Agent 4B] Isolation Forest fallback complete."); return df

# Cell zU8-onIgVmyv content (esg_risk_agent)
def esg_risk_agent(df):
    df = df.copy()
    # Ensure necessary columns exist before accessing
    if "scaled_Procurement_Waste_Tons" in df.columns:
        waste = df["scaled_Procurement_Waste_Tons"].astype(float); waste_norm = (waste - waste.min()) / (waste.max() - waste.min() + 1e-6)
        df["Environmental_Score"] = (100 * (1 - waste_norm)).clip(15, 98)
    else:
        df["Environmental_Score"] = 75 # Default if column missing

    if "SubAgent_C_CyberBERT_Risk" in df.columns:
        df["Social_Score"] = (100 * (1 - df["SubAgent_C_CyberBERT_Risk"].astype(float))).clip(20, 99)
    else:
        df["Social_Score"] = 75 # Default if column missing
    
    if "SubAgent_B_LedgerBERT_Risk" in df.columns:
        df["Governance_Score"] = (100 * (1 - df["SubAgent_B_LedgerBERT_Risk"].astype(float))).clip(10, 97)
    else:
        df["Governance_Score"] = 75 # Default if column missing

    df["Overall_ESG_Score"] = (df["Environmental_Score"] + df["Social_Score"] + df["Governance_Score"]) / 3

    def classify(row):
        # Ensure Anomaly_Indicator and IForest_Indicator exist or default
        anomaly_status = row.get("Anomaly_Indicator", "Normal Verified Ledger")
        iforest_status = row.get("IForest_Indicator", "Normal Verified Ledger")
        
        if anomaly_status == "CRITICAL PROFILE ALERT" or row["Overall_ESG_Score"] < 50: return "High"
        elif row["Overall_ESG_Score"] < 75 or iforest_status == "CRITICAL PROFILE ALERT": return "Medium"
        return "Low"
    df["ESG_Risk_Classification"] = df.apply(classify, axis=1)
    print("[Agent 5] ESG risk assessment complete."); return df

